function trackCost(
  operation: string,
  cost: number,
  city?: string
): void {
  try {
    const dateKey = new Date().toISOString().split("T")[0]
    const monthKey = dateKey.slice(0, 7)

    const promises: Promise<unknown>[] = [
      kv.hincrbyfloat(`costs:daily:${dateKey}`, operation, cost),
      kv.hincrbyfloat(`costs:monthly:${monthKey}`, operation, cost),
      kv.hincrbyfloat("costs:total", operation, cost),
    ]

    if (city) {
      promises.push(
        kv.hincrbyfloat(`costs:city:${city}`, operation, cost)
      )
    }

    // Fire-and-forget: run all increments in parallel, ignore failures
    void Promise.all(promises).catch(() => {})
  } catch {
    // Swallow any synchronous errors (e.g., kv not configured)
  }
}
